pub struct CliParser {
    name: String,
    flags: HashMap<String, FlagDef>,
    subcommands: HashMap<String, CliParser>,
}

pub struct ParsedArgs {
    pub flags: HashMap<String, String>,
    pub positional: Vec<String>,
    pub subcommand: Option<(String, Box<ParsedArgs>)>,
}

pub fn new(name: &str) -> Self {
    Self { name: name.to_string(), flags: HashMap::new(), subcommands: HashMap::new() }
}

pub fn flag(mut self, name: &str, short: Option<char>, takes_value: bool) -> Self {
    self.flags.insert(name.to_string(), FlagDef {
        short, takes_value, default: None,
    });
    self
}

pub fn subcommand(mut self, name: &str, parser: CliParser) -> Self {
    self.subcommands.insert(name.to_string(), parser);
    self
}

pub fn parse(&self, args: &[String]) -> Result<ParsedArgs, String> {
    let mut flags = HashMap::new();
    let mut positional = Vec::new();
    let mut i = 0;
    while i < args.len() {
        let arg = &args[i];
        if arg.starts_with("--") {
            let name = &arg[2..];
            if let Some(def) = self.flags.get(name) {
                if def.takes_value {
                    i += 1;
                    flags.insert(name.to_string(), args[i].clone());
                } else {
                    flags.insert(name.to_string(), "true".to_string());
                }
            }
        } else if let Some(sub) = self.subcommands.get(arg.as_str()) {
            let sub_result = sub.parse(&args[i + 1..])?;
            return Ok(ParsedArgs {
                flags,
                positional,
                subcommand: Some((arg.clone(), Box::new(sub_result))),
            });
        } else {
            positional.push(arg.clone());
        }
        i += 1;
    }
    Ok(ParsedArgs { flags, positional, subcommand: None })
}
